<?php

declare(strict_types=1);

function sf_pch_checkpoint_offsets():array{return['15m'=>900,'1h'=>3600,'6h'=>21600,'24h'=>86400,'72h'=>259200];}
function sf_pch_seed_checkpoints(int $runId,?int $baseTimestamp=null):bool{$run=sf_pch_run($runId);if(!$run||!sf_pch_ready())return false;$base=$baseTimestamp??time();$ok=true;foreach(sf_pch_checkpoint_offsets() as$key=>$offset)$ok=sf_admin_execute("INSERT IGNORE INTO production_hypercare_checkpoints (run_id,checkpoint_key,scheduled_for) VALUES (?,?,?)",[$runId,$key,date('Y-m-d H:i:s',$base+$offset)])&&$ok;return$ok;}
function sf_pch_checkpoint(int $id):?array{return sf_pch_ready()&&$id>0?sf_admin_fetch_one('SELECT * FROM production_hypercare_checkpoints WHERE id=? LIMIT 1',[$id]):null;}
function sf_pch_metrics(int $checkpointId):array{return sf_pch_ready()&&$checkpointId>0?sf_admin_fetch_all('SELECT * FROM production_hypercare_metrics WHERE checkpoint_id=? ORDER BY metric_key',[$checkpointId]):[];}
function sf_pch_metric_threshold(string $key):array{$t=sf_pch_thresholds();$map=[
 'availability_pct'=>[99.0,'min','percent'],'p95_latency_ms'=>[$t['p95_latency_ms'],'max','ms'],'error_rate_pct'=>[$t['error_rate_pct'],'max','percent'],'payment_failure_rate_pct'=>[$t['payment_failure_rate_pct'],'max','percent'],'media_failure_rate_pct'=>[$t['media_failure_rate_pct'],'max','percent'],'email_failure_rate_pct'=>[10.0,'max','percent'],'queue_depth'=>[$t['queue_depth'],'max','count'],'critical_incidents'=>[max(0,$t['critical_incidents']-1),'max','count'],'signup_count'=>[0,'min','count'],'subscription_count'=>[0,'min','count'],'revenue_cents'=>[0,'min','cents'],'refund_count'=>[0,'min','count'],'support_open_count'=>[0,'min','count']];return$map[$key]??[0,'min','value'];}
function sf_pch_metric_status(float $value,float $threshold,string $direction):string{return$direction==='max'?($value<=$threshold?'healthy':'critical'):($value>=$threshold?'healthy':'critical');}
function sf_pch_record_checkpoint(int $checkpointId,array $metrics,string $summary,string $reference=''):array{$checkpoint=sf_pch_checkpoint($checkpointId);if(!$checkpoint)return['ok'=>false,'message'=>'Checkpoint not found.'];if(strtotime((string)$checkpoint['scheduled_for'])>time())return['ok'=>false,'message'=>'Checkpoint is not due yet.'];$run=sf_pch_run((int)$checkpoint['run_id']);if(!$run||sf_pch_locked($run))return['ok'=>false,'message'=>'Cutover run is immutable.'];$pdo=sf_admin_db();if(!$pdo)return['ok'=>false,'message'=>'Database unavailable.'];$blockers=0;$healthy=0;$total=0;$normalized=[];try{$pdo->beginTransaction();foreach($metrics as$key=>$raw){if(!is_numeric($raw)||!preg_match('/^[a-z0-9_]{3,100}$/',$key))continue;[$threshold,$direction,$unit]=sf_pch_metric_threshold($key);$value=(float)$raw;$status=sf_pch_metric_status($value,(float)$threshold,$direction);if($status==='critical')$blockers++;if($status==='healthy')$healthy++;$total++;$normalized[$key]=['value'=>$value,'threshold'=>$threshold,'direction'=>$direction,'status'=>$status];$s=$pdo->prepare("INSERT INTO production_hypercare_metrics (checkpoint_id,metric_key,metric_value,metric_unit,threshold_value,threshold_direction,metric_status,source_reference,recorded_at) VALUES (?,?,?,?,?,?,?,?,NOW()) ON DUPLICATE KEY UPDATE metric_value=VALUES(metric_value),metric_unit=VALUES(metric_unit),threshold_value=VALUES(threshold_value),threshold_direction=VALUES(threshold_direction),metric_status=VALUES(metric_status),source_reference=VALUES(source_reference),recorded_at=NOW()");$s->execute([$checkpointId,$key,$value,$unit,$threshold,$direction,$status,$reference?:null]);}$score=$total?(int)round($healthy/$total*100):0;$status=$total>0&&$blockers===0?'passed':'failed';$pdo->prepare('UPDATE production_hypercare_checkpoints SET checkpoint_status=?,health_score=?,blocker_count=?,summary_json=?,completed_by_user_id=?,completed_at=NOW() WHERE id=?')->execute([$status,$score,$blockers,json_encode(['summary'=>sf_pch_text($summary,4000),'metrics'=>$normalized],JSON_UNESCAPED_SLASHES),sf_current_user_id()?:null,$checkpointId]);$pdo->commit();sf_pch_event((int)$checkpoint['run_id'],'hypercare.'.$checkpoint['checkpoint_key'],$summary,['checkpoint_id'=>$checkpointId,'status'=>$status,'health_score'=>$score,'blockers'=>$blockers],'verified');sf_pch_evaluate_thresholds((int)$checkpoint['run_id']);return['ok'=>$status==='passed','status'=>$status,'score'=>$score,'blockers'=>$blockers];}catch(Throwable$e){if($pdo->inTransaction())$pdo->rollBack();return['ok'=>false,'message'=>$e->getMessage()];}}
function sf_pch_evaluate_thresholds(int $runId):array{$run=sf_pch_run($runId);if(!$run)return['recommended'=>false,'reasons'=>[]];$reasons=[];if(sf_pch_critical_incidents()>=(int)sf_pch_thresholds()['critical_incidents'])$reasons[]='Critical incident threshold reached.';$latest=sf_admin_fetch_one("SELECT c.* FROM production_hypercare_checkpoints c WHERE c.run_id=? AND c.checkpoint_status='failed' ORDER BY c.completed_at DESC,id DESC LIMIT 1",[$runId]);if($latest){$metrics=sf_pch_metrics((int)$latest['id']);foreach($metrics as$m)if(($m['metric_status']??'')==='critical')$reasons[]=$m['metric_key'].' exceeded threshold.';}$recommended=!empty($reasons);sf_admin_execute('UPDATE production_cutover_runs SET rollback_recommended=?,rollback_reason=? WHERE id=?',[$recommended?1:0,$recommended?sf_pch_text(implode(' ',array_unique($reasons)),2000):null,$runId]);if($recommended)sf_pch_event($runId,'rollback.recommended','Automated rollback recommendation generated.',['reasons'=>$reasons],'verified');return['recommended'=>$recommended,'reasons'=>array_values(array_unique($reasons))];}
function sf_pch_certificate_for_run(int $runId):?array{return sf_pch_ready()?sf_admin_fetch_one('SELECT * FROM production_verification_certificates WHERE run_id=? LIMIT 1',[$runId]):null;}
function sf_pch_issue_certificate(int $runId,string $knownIssues,string $handoffNotes,array $baselines=[]):array{$run=sf_pch_run($runId);if(!$run||sf_pch_locked($run)&&($run['run_status']??'')!=='stabilizing')return['ok'=>false,'message'=>'Run is missing or immutable.'];sf_pch_recalculate($runId);$run=sf_pch_run($runId)?:$run;$checkpoints=sf_pch_checkpoints($runId);$allCheckpoints=count($checkpoints)===5&&!array_filter($checkpoints,static fn($c)=>($c['checkpoint_status']??'')!=='passed');$handoffNotes=sf_pch_text($handoffNotes,30000);if((float)$run['overall_score']<96||(int)$run['failed_checks']>0||(int)$run['pending_checks']>1||!$allCheckpoints||(int)$run['traffic_percent']!==100||empty($run['deployed_at'])||!empty($run['rollback_recommended'])||strlen($handoffNotes)<40)return['ok'=>false,'message'=>'Cutover checks, 100% traffic, a clear rollback state, all five due hypercare checkpoints, and detailed handoff notes are required.'];$issues=array_values(array_filter(array_map('trim',preg_split('/\r?\n/',$knownIssues)?:[])));$payload=['run_key'=>$run['run_key'],'commit'=>$run['target_commit_sha'],'artifact_sha256'=>$run['artifact_sha256'],'issued_at'=>gmdate('c'),'known_issues'=>$issues,'handoff_notes'=>$handoffNotes,'baselines'=>$baselines];$certificateSha=hash('sha256',json_encode($payload,JSON_UNESCAPED_SLASHES|JSON_INVALID_UTF8_SUBSTITUTE));$ok=sf_admin_execute("INSERT INTO production_verification_certificates (certificate_key,run_id,target_commit_sha,artifact_sha256,certificate_status,overall_score,availability_baseline,payment_success_baseline,media_success_baseline,membership_baseline,revenue_baseline_cents,known_issues_json,handoff_notes,certificate_sha256,issued_by_user_id,issued_at) VALUES (?,?,?,?, 'verified',100,?,?,?,?,?,?,?,?,?,NOW())",[sf_pch_uuid(),$runId,$run['target_commit_sha'],$run['artifact_sha256'],$baselines['availability_pct']??null,$baselines['payment_success_pct']??null,$baselines['media_success_pct']??null,$baselines['membership_count']??null,$baselines['revenue_cents']??null,json_encode($issues,JSON_UNESCAPED_SLASHES),$handoffNotes,$certificateSha,sf_current_user_id()?:null]);if(!$ok)return['ok'=>false,'message'=>'Certificate could not be stored.'];sf_pch_record($runId,'certificate.production','passed','Production verification certificate '.$certificateSha.' issued.',['certificate_sha256'=>$certificateSha]);sf_admin_execute("UPDATE production_cutover_runs SET run_status='completed',overall_score=100,stabilized_at=COALESCE(stabilized_at,NOW()),completed_at=NOW(),updated_by_user_id=? WHERE id=?",[sf_current_user_id()?:null,$runId]);sf_pch_event($runId,'certificate.issued','Production cutover and hypercare completed.',['certificate_sha256'=>$certificateSha,'known_issues'=>$issues],'verified');return['ok'=>true,'message'=>'Production verification certificate issued.','certificate_sha256'=>$certificateSha];}
function sf_pch_status_secret():string{return trim((string)(getenv('SF_PRODUCTION_STATUS_SECRET')?:getenv('SF_PRODUCTION_CUTOVER_SECRET')?:''));}
function sf_pch_event_secret():string{return trim((string)(getenv('SF_PRODUCTION_CUTOVER_EVENT_SECRET')?:''));}
function sf_pch_signature_valid(string $raw,string $provided,string $secret):bool{$provided=preg_replace('/^sha256=/i','',trim($provided))??'';return strlen($secret)>=32&&strlen($provided)===64&&hash_equals(hash_hmac('sha256',$raw,$secret),$provided);}
function sf_pch_ingest_event(array $run,array $payload):array{$eventId=sf_pch_text($payload['event_id']??'',190);$type=sf_pch_text($payload['event_type']??'',120);if($eventId===''||$type==='')return['ok'=>false,'message'=>'Event identity is required.'];$message=sf_pch_text($payload['message']??'Production cutover event received.',2000);if(!sf_pch_event((int)$run['id'],$type,$message,$payload,'processed',$eventId))return['ok'=>true,'status'=>'duplicate_or_rejected'];$checkKey=(string)($payload['check_key']??'');$result=(string)($payload['result']??'');if(isset(sf_pch_catalog()[$checkKey])&&in_array($result,['passed','failed','running'],true))sf_pch_record((int)$run['id'],$checkKey,$result,$message,['source_event_id'=>$eventId]);if(isset($payload['traffic_percent']))sf_pch_set_traffic((int)$run['id'],(int)$payload['traffic_percent'],$message);return['ok'=>true,'status'=>'processed'];}
